import React, { useState, useRef } from 'react';
import * as XLSX from 'xlsx';
import Papa from 'papaparse';
import { accessService } from '../services/accessService';
import { userService } from '../services/userService';
import './BulkImportModal.css';

const BulkImportModal = ({ isOpen, onClose, onImport, mapId, isOwner }) => {
  const [file, setFile] = useState(null);
  const [previewData, setPreviewData] = useState([]);
  const [selectedRole, setSelectedRole] = useState('learner');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [step, setStep] = useState('upload');
  const [importResult, setImportResult] = useState(null);
  const [checkingUsers, setCheckingUsers] = useState(false);
  const fileInputRef = useRef(null);

  if (!isOpen || !isOwner) return null;

  const handleFileUpload = (e) => {
    const uploadedFile = e.target.files[0];
    if (!uploadedFile) return;

    setFile(uploadedFile);
    setError('');
    
    const fileExtension = uploadedFile.name.split('.').pop().toLowerCase();
    
    if (fileExtension === 'csv') {
      parseCSV(uploadedFile);
    } else if (fileExtension === 'xlsx' || fileExtension === 'xls') {
      parseExcel(uploadedFile);
    } else {
      setError('РџРѕРґРґРµСЂР¶РёРІР°СЋС‚СЃСЏ С‚РѕР»СЊРєРѕ С„Р°Р№Р»С‹ .xlsx, .xls Рё .csv');
      setFile(null);
    }
  };

  const parseCSV = (file) => {
    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        if (results.data && results.data.length > 0) {
          processData(results.data);
        } else {
          setError('Р¤Р°Р№Р» РїСѓСЃС‚ РёР»Рё РёРјРµРµС‚ РЅРµРїСЂР°РІРёР»СЊРЅС‹Р№ С„РѕСЂРјР°С‚');
        }
      },
      error: (error) => {
        setError('РћС€РёР±РєР° РїР°СЂСЃРёРЅРіР° CSV: ' + error.message);
      }
    });
  };

  const parseExcel = (file) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target.result);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json(firstSheet);
        
        if (jsonData && jsonData.length > 0) {
          processData(jsonData);
        } else {
          setError('Р¤Р°Р№Р» РїСѓСЃС‚ РёР»Рё РёРјРµРµС‚ РЅРµРїСЂР°РІРёР»СЊРЅС‹Р№ С„РѕСЂРјР°С‚');
        }
      } catch (err) {
        setError('РћС€РёР±РєР° РїР°СЂСЃРёРЅРіР° Excel: ' + err.message);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const processData = (data) => {
    const firstRow = data[0];
    const possibleUsernameFields = ['username', 'login', 'user', 'name', 'Р»РѕРіРёРЅ', 'РїРѕР»СЊР·РѕРІР°С‚РµР»СЊ'];
    
    let usernameField = null;
    for (const field of possibleUsernameFields) {
      if (firstRow[field] !== undefined) {
        usernameField = field;
        break;
      }
    }
    
    if (!usernameField) {
      usernameField = Object.keys(firstRow)[0];
    }
    
    const usernames = data
      .map(row => row[usernameField]?.toString().trim())
      .filter(username => username && username.length > 0);
    
    if (usernames.length === 0) {
      setError('РќРµ РЅР°Р№РґРµРЅРѕ Р»РѕРіРёРЅРѕРІ РІ С„Р°Р№Р»Рµ');
      return;
    }
    
    const uniqueUsernames = [...new Set(usernames)];
    
    setPreviewData(uniqueUsernames.map(username => ({
      username,
      status: 'checking',
      message: 'РџСЂРѕРІРµСЂРєР°...',
      currentRole: null,
      canUpdate: false,
      userId: null,
      // Р’РђР–РќРћ: РґР»СЏ РІСЃРµС… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№ СѓСЃС‚Р°РЅР°РІР»РёРІР°РµРј РІС‹Р±СЂР°РЅРЅСѓСЋ Р°РІС‚РѕСЂРѕРј СЂРѕР»СЊ
      selectedRole: selectedRole
    })));
    setStep('preview');
    
    checkUsers(uniqueUsernames);
  };

  const checkUsers = async (usernames) => {
    setCheckingUsers(true);
    
    // РџРѕР»СѓС‡Р°РµРј С‚РµРєСѓС‰РёС… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№ СЃ РґРѕСЃС‚СѓРїРѕРј
    let existingUsers = [];
    try {
      const accessData = await accessService.getMapAccess(mapId);
      existingUsers = Array.isArray(accessData) ? accessData : [];
    } catch (error) {
      console.error('РћС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё СЃСѓС‰РµСЃС‚РІСѓСЋС‰РёС… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№:', error);
    }
    
    const existingUsersMap = new Map();
    existingUsers.forEach(user => {
      existingUsersMap.set(user.username?.toLowerCase(), {
        role: user.role,
        accessId: user.id,
        userId: user.userId || user.id
      });
    });
    
    const checkedData = [];
    
    for (const username of usernames) {
      let status = 'pending';
      let message = '';
      let currentRole = null;
      let canUpdate = false;
      let userId = null;
      
      const existingUser = existingUsersMap.get(username.toLowerCase());
      
      if (existingUser) {
        currentRole = existingUser.role;
        
        // РџСЂРѕРІРµСЂСЏРµРј, РѕС‚Р»РёС‡Р°РµС‚СЃСЏ Р»Рё С‚РµРєСѓС‰Р°СЏ СЂРѕР»СЊ РѕС‚ РІС‹Р±СЂР°РЅРЅРѕР№ Р°РІС‚РѕСЂРѕРј
        if (currentRole !== selectedRole) {
          status = 'exists';
          // Р’ СЃРѕРѕР±С‰РµРЅРёРё РїРѕРєР°Р·С‹РІР°РµРј, РєР°РєР°СЏ СЂРѕР»СЊ Р±СѓРґРµС‚ СѓСЃС‚Р°РЅРѕРІР»РµРЅР°
          message = `РРјРµРµС‚ РґРѕСЃС‚СѓРї РєР°Рє ${currentRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}, Р±СѓРґРµС‚ РёР·РјРµРЅРµРЅРѕ РЅР° ${selectedRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}`;
          canUpdate = true;
        } else {
          status = 'exists_same';
          message = `РЈР¶Рµ РёРјРµРµС‚ РґРѕСЃС‚СѓРї (${currentRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}) вЂ” СЂРѕР»СЊ СЃРѕРІРїР°РґР°РµС‚`;
          canUpdate = false;
        }
        userId = existingUser.userId;
      } else {
        try {
          const userCheck = await userService.checkUserExists(username);
          
          if (userCheck.exists) {
            status = 'valid';
            message = `Р“РѕС‚РѕРІ Рє РїСЂРёРіР»Р°С€РµРЅРёСЋ РєР°Рє ${selectedRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}`;
            canUpdate = true;
            userId = userCheck.userId;
          } else {
            status = 'not_found';
            message = userCheck.message || 'РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ РЅР°Р№РґРµРЅ';
            canUpdate = false;
          }
        } catch (error) {
          console.error('РћС€РёР±РєР° РїСЂРѕРІРµСЂРєРё РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ:', error);
          status = 'error';
          message = error.response?.data?.message || 'РћС€РёР±РєР° РїСЂРѕРІРµСЂРєРё РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ';
          canUpdate = false;
        }
      }
      
      checkedData.push({
        username,
        status,
        message,
        currentRole,
        canUpdate,
        userId,
        // Р’РђР–РќРћ: РґР»СЏ РІСЃРµС… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№ СѓСЃС‚Р°РЅР°РІР»РёРІР°РµРј РІС‹Р±СЂР°РЅРЅСѓСЋ Р°РІС‚РѕСЂРѕРј СЂРѕР»СЊ
        selectedRole: selectedRole
      });
    }
    
    setPreviewData(checkedData);
    setCheckingUsers(false);
  };

  // Р¤СѓРЅРєС†РёСЏ РґР»СЏ РѕР±РЅРѕРІР»РµРЅРёСЏ РІС‹Р±СЂР°РЅРЅРѕР№ СЂРѕР»Рё РґР»СЏ РІСЃРµС… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№
  const updateAllRoles = (newRole) => {
    setSelectedRole(newRole);
    setPreviewData(prev => prev.map(user => {
      const newSelectedRole = newRole;
      let newStatus = user.status;
      let newMessage = user.message;
      let newCanUpdate = user.canUpdate;
      
      // РћР±РЅРѕРІР»СЏРµРј СЃС‚Р°С‚СѓСЃ РґР»СЏ СЃСѓС‰РµСЃС‚РІСѓСЋС‰РёС… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№
      if (user.currentRole) {
        if (user.currentRole !== newRole) {
          newStatus = 'exists';
          newMessage = `РРјРµРµС‚ РґРѕСЃС‚СѓРї РєР°Рє ${user.currentRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}, Р±СѓРґРµС‚ РёР·РјРµРЅРµРЅРѕ РЅР° ${newRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}`;
          newCanUpdate = true;
        } else {
          newStatus = 'exists_same';
          newMessage = `РЈР¶Рµ РёРјРµРµС‚ РґРѕСЃС‚СѓРї (${user.currentRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}) вЂ” СЂРѕР»СЊ СЃРѕРІРїР°РґР°РµС‚`;
          newCanUpdate = false;
        }
      } else if (user.status === 'valid') {
        // Р”Р»СЏ РЅРѕРІС‹С… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№ РѕР±РЅРѕРІР»СЏРµРј СЃРѕРѕР±С‰РµРЅРёРµ
        newMessage = `Р“РѕС‚РѕРІ Рє РїСЂРёРіР»Р°С€РµРЅРёСЋ РєР°Рє ${newRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}`;
        newCanUpdate = true;
      }
      
      return {
        ...user,
        selectedRole: newSelectedRole,
        status: newStatus,
        message: newMessage,
        canUpdate: newCanUpdate
      };
    }));
  };

  const updateUserRole = (index, newRole) => {
    setPreviewData(prev => {
      const updated = [...prev];
      const user = updated[index];
      user.selectedRole = newRole;
      
      // РћР±РЅРѕРІР»СЏРµРј СЃС‚Р°С‚СѓСЃ РґР»СЏ СЃСѓС‰РµСЃС‚РІСѓСЋС‰РµРіРѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
      if (user.currentRole) {
        if (user.currentRole !== newRole) {
          user.status = 'exists';
          user.message = `РРјРµРµС‚ РґРѕСЃС‚СѓРї РєР°Рє ${user.currentRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}, Р±СѓРґРµС‚ РёР·РјРµРЅРµРЅРѕ РЅР° ${newRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}`;
          user.canUpdate = true;
        } else {
          user.status = 'exists_same';
          user.message = `РЈР¶Рµ РёРјРµРµС‚ РґРѕСЃС‚СѓРї (${user.currentRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}) вЂ” СЂРѕР»СЊ СЃРѕРІРїР°РґР°РµС‚`;
          user.canUpdate = false;
        }
      } else if (user.status === 'valid') {
        user.message = `Р“РѕС‚РѕРІ Рє РїСЂРёРіР»Р°С€РµРЅРёСЋ РєР°Рє ${newRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}`;
        user.canUpdate = true;
      }
      
      return updated;
    });
  };

  const handleImport = async () => {
    // РћС‚Р±РёСЂР°РµРј РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№ РґР»СЏ РёРјРїРѕСЂС‚Р°:
    // 1. РќРѕРІС‹Рµ РїРѕР»СЊР·РѕРІР°С‚РµР»Рё (valid)
    // 2. РЎСѓС‰РµСЃС‚РІСѓСЋС‰РёРµ РїРѕР»СЊР·РѕРІР°С‚РµР»Рё, Сѓ РєРѕС‚РѕСЂС‹С… СЂРѕР»СЊ РѕС‚Р»РёС‡Р°РµС‚СЃСЏ РѕС‚ РІС‹Р±СЂР°РЅРЅРѕР№ (exists)
    const usersToImport = previewData.filter(user => 
      user.status === 'valid' || (user.status === 'exists' && user.canUpdate)
    );
    
    if (usersToImport.length === 0) {
      setError('РќРµС‚ РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№ РґР»СЏ РёРјРїРѕСЂС‚Р°');
      return;
    }
    
    setLoading(true);
    setStep('importing');
    
    let successCount = 0;
    let errorCount = 0;
    let updateCount = 0;
    let newCount = 0;
    
    for (const user of usersToImport) {
      try {
        if (user.status === 'exists') {
          // РћР±РЅРѕРІР»СЏРµРј СЂРѕР»СЊ СЃСѓС‰РµСЃС‚РІСѓСЋС‰РµРіРѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
          const accessData = await accessService.getMapAccess(mapId);
          const existingUser = accessData.find(u => u.username?.toLowerCase() === user.username.toLowerCase());
          
          if (existingUser && existingUser.role !== user.selectedRole) {
            await accessService.updateRole(existingUser.id, user.selectedRole);
            updateCount++;
            
            const index = previewData.findIndex(u => u.username === user.username);
            if (index !== -1) {
              previewData[index].status = 'success';
              previewData[index].message = `Р РѕР»СЊ РёР·РјРµРЅРµРЅР° РЅР° ${user.selectedRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}`;
            }
          }
          successCount++;
        } else if (user.status === 'valid') {
          // РЎРѕР·РґР°РµРј РЅРѕРІРѕРіРѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
          await accessService.invite(mapId, user.username, user.selectedRole);
          
          const index = previewData.findIndex(u => u.username === user.username);
          if (index !== -1) {
            previewData[index].status = 'success';
            previewData[index].message = `РџСЂРёРіР»Р°С€С‘РЅ РєР°Рє ${user.selectedRole === 'learner' ? 'РѕР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'РЅР°Р±Р»СЋРґР°С‚РµР»СЊ'}`;
          }
          newCount++;
          successCount++;
        }
      } catch (error) {
        console.error('РћС€РёР±РєР° РїСЂРё РёРјРїРѕСЂС‚Рµ:', error);
        const index = previewData.findIndex(u => u.username === user.username);
        if (index !== -1) {
          previewData[index].status = 'error';
          previewData[index].message = error.response?.data?.message || error.message || 'РћС€РёР±РєР° РѕРїРµСЂР°С†РёРё';
        }
        errorCount++;
      }
      
      setPreviewData([...previewData]);
    }
    
    setImportResult({
      total: usersToImport.length,
      success: successCount,
      error: errorCount,
      updated: updateCount,
      new: newCount,
      skipped: previewData.filter(u => u.status === 'exists_same' || u.status === 'not_found').length
    });
    
    setLoading(false);
    
    if (successCount > 0) {
      onImport(successCount);
    }
  };

  const downloadTemplate = () => {
    const template = [
      { username: 'ivanov' },
      { username: 'petrov' },
      { username: 'sidorov' }
    ];
    
    const ws = XLSX.utils.json_to_sheet(template);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'РЁР°Р±Р»РѕРЅ');
    XLSX.writeFile(wb, 'template_users.xlsx');
  };

  const resetAndClose = () => {
    setFile(null);
    setPreviewData([]);
    setStep('upload');
    setError('');
    setImportResult(null);
    setSelectedRole('learner');
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
    onClose();
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'valid':
        return <span className="material-icons status-icon valid">check_circle</span>;
      case 'exists':
        return <span className="material-icons status-icon exists">update</span>;
      case 'exists_same':
        return <span className="material-icons status-icon exists-same">check_circle</span>;
      case 'not_found':
        return <span className="material-icons status-icon not-found">error</span>;
      case 'success':
        return <span className="material-icons status-icon success">check_circle</span>;
      case 'error':
        return <span className="material-icons status-icon error">error</span>;
      case 'skipped':
        return <span className="material-icons status-icon skipped">skip_next</span>;
      case 'checking':
        return <span className="material-icons status-icon checking">schedule</span>;
      default:
        return null;
    }
  };

  const getStatusText = (status, message) => {
    switch (status) {
      case 'valid':
        return <span className="status-text valid">{message || 'Р“РѕС‚РѕРІ Рє РїСЂРёРіР»Р°С€РµРЅРёСЋ'}</span>;
      case 'exists':
        return <span className="status-text exists">{message || 'Р‘СѓРґРµС‚ РѕР±РЅРѕРІР»РµРЅР° СЂРѕР»СЊ'}</span>;
      case 'exists_same':
        return <span className="status-text exists-same">{message || 'Р РѕР»СЊ СѓР¶Рµ СЃРѕРѕС‚РІРµС‚СЃС‚РІСѓРµС‚'}</span>;
      case 'not_found':
        return <span className="status-text not-found">{message || 'РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ РЅР°Р№РґРµРЅ'}</span>;
      case 'success':
        return <span className="status-text success">{message || 'РЈСЃРїРµС€РЅРѕ'}</span>;
      case 'error':
        return <span className="status-text error">{message || 'РћС€РёР±РєР°'}</span>;
      case 'skipped':
        return <span className="status-text skipped">{message || 'РџСЂРѕРїСѓС‰РµРЅ'}</span>;
      case 'checking':
        return <span className="status-text checking">{message || 'РџСЂРѕРІРµСЂРєР°...'}</span>;
      default:
        return <span className="status-text">{message}</span>;
    }
  };

  const renderContent = () => {
    switch (step) {
      case 'upload':
        return (
          <>
            <div className="upload-area">
              <div className="upload-icon">
                <span className="material-icons">cloud_upload</span>
              </div>
              <p>РџРµСЂРµС‚Р°С‰РёС‚Рµ С„Р°Р№Р» СЃСЋРґР° РёР»Рё РЅР°Р¶РјРёС‚Рµ РґР»СЏ РІС‹Р±РѕСЂР°</p>
              <input
                ref={fileInputRef}
                type="file"
                accept=".xlsx,.xls,.csv"
                onChange={handleFileUpload}
                className="file-input"
              />
              <button className="template-btn" onClick={downloadTemplate}>
                <span className="material-icons">file_download</span>
                РЎРєР°С‡Р°С‚СЊ С€Р°Р±Р»РѕРЅ
              </button>
            </div>
            
            <div className="import-options">
              <h4>РќР°СЃС‚СЂРѕР№РєРё РёРјРїРѕСЂС‚Р°</h4>
              <div className="role-selector">
                <label>Р РѕР»СЊ РґР»СЏ РІСЃРµС… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№:</label>
                <select 
                  value={selectedRole} 
                  onChange={(e) => updateAllRoles(e.target.value)}
                >
                  <option value="learner">рџ“љ РћР±СѓС‡Р°СЋС‰РёР№СЃСЏ</option>
                  <option value="observer">рџ‘ЃпёЏ РќР°Р±Р»СЋРґР°С‚РµР»СЊ</option>
                </select>
              </div>
              <p className="role-hint">
                Р’С‹Р±СЂР°РЅРЅР°СЏ СЂРѕР»СЊ Р±СѓРґРµС‚ РїСЂРёРјРµРЅРµРЅР° РєРѕ РІСЃРµРј РїРѕР»СЊР·РѕРІР°С‚РµР»СЏРј РІ СЃРїРёСЃРєРµ.
                {selectedRole === 'learner' 
                  ? ' РћР±СѓС‡Р°СЋС‰РёРµСЃСЏ Р±СѓРґСѓС‚ РѕС‚РєСЂС‹РІР°С‚СЊ СѓР·Р»С‹ С‡РµСЂРµР· С‚РµСЃС‚С‹.' 
                  : ' РќР°Р±Р»СЋРґР°С‚РµР»Рё СѓРІРёРґСЏС‚ РІСЃРµ СѓР·Р»С‹ СЃСЂР°Р·Сѓ.'}
              </p>
            </div>
            
            <div className="info-box">
              <span className="material-icons">info</span>
              <div>
                <strong>Р¤РѕСЂРјР°С‚ С„Р°Р№Р»Р°:</strong>
                <p>Excel (.xlsx, .xls) РёР»Рё CSV С„Р°Р№Р» СЃ РєРѕР»РѕРЅРєРѕР№ "username" (Р»РѕРіРёРЅ).</p>
                <p>РџРѕРґРґРµСЂР¶РёРІР°СЋС‚СЃСЏ С‚Р°РєР¶Рµ РЅР°Р·РІР°РЅРёСЏ РєРѕР»РѕРЅРѕРє: login, user, name, Р»РѕРіРёРЅ, РїРѕР»СЊР·РѕРІР°С‚РµР»СЊ</p>
                <p className="info-note">
                  <span className="material-icons">info_outline</span>
                  <strong>Р’Р°Р¶РЅРѕ:</strong> Р”Р»СЏ РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№, РєРѕС‚РѕСЂС‹Рµ СѓР¶Рµ РёРјРµСЋС‚ РґРѕСЃС‚СѓРї, РёС… СЂРѕР»СЊ Р±СѓРґРµС‚ РёР·РјРµРЅРµРЅР° РЅР° РІС‹Р±СЂР°РЅРЅСѓСЋ.
                </p>
              </div>
            </div>
          </>
        );
        
      case 'preview':
        return (
          <>
            <div className="preview-header">
              <h4>
                РџСЂРµРґРїСЂРѕСЃРјРѕС‚СЂ ({previewData.length} РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№)
                {checkingUsers && <span className="checking-badge">РџСЂРѕРІРµСЂРєР°...</span>}
              </h4>
              <div className="preview-actions">
                <button className="back-btn" onClick={() => setStep('upload')}>
                  <span className="material-icons">arrow_back</span>
                  РќР°Р·Р°Рґ
                </button>
              </div>
            </div>
            
            <div className="role-batch-update">
              <label>РР·РјРµРЅРёС‚СЊ СЂРѕР»СЊ РґР»СЏ РІСЃРµС…:</label>
              <select 
                value={selectedRole}
                onChange={(e) => updateAllRoles(e.target.value)}
                className="batch-role-select"
              >
                <option value="learner">рџ“љ РћР±СѓС‡Р°СЋС‰РёР№СЃСЏ</option>
                <option value="observer">рџ‘ЃпёЏ РќР°Р±Р»СЋРґР°С‚РµР»СЊ</option>
              </select>
            </div>
            
            <div className="preview-table-container">
              <table className="preview-table">
                <thead>
                  <tr>
                    <th>в„–</th>
                    <th>Р›РѕРіРёРЅ</th>
                    <th>РўРµРєСѓС‰Р°СЏ СЂРѕР»СЊ</th>
                    <th>РќРѕРІР°СЏ СЂРѕР»СЊ</th>
                    <th>РЎС‚Р°С‚СѓСЃ</th>
                  </tr>
                </thead>
                <tbody>
                  {previewData.slice(0, 50).map((user, index) => (
                    <tr key={index} className={`status-row ${user.status}`}>
                      <td>{index + 1}</td>
                      <td className="username-cell">{user.username}</td>
                      <td className="current-role-cell">
                        {user.currentRole ? (
                          <span className={`role-badge ${user.currentRole}`}>
                            {user.currentRole === 'learner' ? 'рџ“љ РћР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'рџ‘ЃпёЏ РќР°Р±Р»СЋРґР°С‚РµР»СЊ'}
                          </span>
                        ) : (
                          <span className="role-badge none">вЂ”</span>
                        )}
                      </td>
                      <td className="new-role-cell">
                        {user.canUpdate || user.status === 'valid' ? (
                          <select 
                            value={user.selectedRole}
                            onChange={(e) => updateUserRole(index, e.target.value)}
                            className={`role-select-small editable ${user.status === 'exists' ? 'update-mode' : ''}`}
                          >
                            <option value="learner">рџ“љ РћР±СѓС‡Р°СЋС‰РёР№СЃСЏ</option>
                            <option value="observer">рџ‘ЃпёЏ РќР°Р±Р»СЋРґР°С‚РµР»СЊ</option>
                          </select>
                        ) : (
                          <span className="role-select-small disabled">
                            {user.status === 'exists_same' ? 
                              (user.selectedRole === 'learner' ? 'рџ“љ РћР±СѓС‡Р°СЋС‰РёР№СЃСЏ' : 'рџ‘ЃпёЏ РќР°Р±Р»СЋРґР°С‚РµР»СЊ') : 
                              'вЂ”'}
                          </span>
                        )}
                      </td>
                      <td className="status-cell">
                        <div className="status-wrapper">
                          {getStatusIcon(user.status)}
                          {getStatusText(user.status, user.message)}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {previewData.length > 50 && (
                <p className="preview-note">РџРѕРєР°Р·Р°РЅРѕ РїРµСЂРІС‹С… 50 РёР· {previewData.length} РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№</p>
              )}
            </div>
            
            <div className="import-stats">
              <div className="stat-item valid">
                <span className="material-icons">person_add</span>
                <span>РќРѕРІС‹Рµ: {previewData.filter(u => u.status === 'valid').length}</span>
              </div>
              <div className="stat-item exists">
                <span className="material-icons">edit</span>
                <span>РћР±РЅРѕРІРёС‚СЊ СЂРѕР»СЊ: {previewData.filter(u => u.status === 'exists' && u.canUpdate).length}</span>
              </div>
              <div className="stat-item exists-same">
                <span className="material-icons">check_circle</span>
                <span>Р РѕР»СЊ СЃРѕРІРїР°РґР°РµС‚: {previewData.filter(u => u.status === 'exists_same').length}</span>
              </div>
              <div className="stat-item not-found">
                <span className="material-icons">error_outline</span>
                <span>РќРµ РЅР°Р№РґРµРЅС‹: {previewData.filter(u => u.status === 'not_found').length}</span>
              </div>
            </div>
            
            <div className="import-actions">
              <button 
                className="import-btn" 
                onClick={handleImport}
                disabled={loading || (previewData.filter(u => u.status === 'valid' || (u.status === 'exists' && u.canUpdate)).length === 0)}
              >
                {loading ? 'РРјРїРѕСЂС‚...' : `РРјРїРѕСЂС‚РёСЂРѕРІР°С‚СЊ (${previewData.filter(u => u.status === 'valid' || (u.status === 'exists' && u.canUpdate)).length})`}
              </button>
            </div>
          </>
        );
        
      case 'importing':
        return (
          <div className="importing-progress">
            <div className="spinner-large"></div>
            <h4>РРјРїРѕСЂС‚ РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№...</h4>
            <p>РџРѕР¶Р°Р»СѓР№СЃС‚Р°, РїРѕРґРѕР¶РґРёС‚Рµ</p>
            <div className="progress-stats">
              <div>вњ… РЈСЃРїРµС€РЅРѕ: {previewData.filter(u => u.status === 'success').length}</div>
              <div>рџ”„ РћР±РЅРѕРІР»РµРЅРѕ: {previewData.filter(u => u.message?.includes('Р РѕР»СЊ РёР·РјРµРЅРµРЅР°')).length}</div>
              <div>вќЊ РћС€РёР±РѕРє: {previewData.filter(u => u.status === 'error').length}</div>
            </div>
          </div>
        );
        
      default:
        return null;
    }
  };

  return (
    <div className="bulk-import-overlay" onClick={resetAndClose}>
      <div className="bulk-import-modal" onClick={e => e.stopPropagation()}>
        <div className="bulk-import-header">
          <h3>
            <span className="material-icons">file_upload</span>
            РњР°СЃСЃРѕРІС‹Р№ РёРјРїРѕСЂС‚ РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№
          </h3>
          <button className="close-btn" onClick={resetAndClose}>
            <span className="material-icons">close</span>
          </button>
        </div>
        
        <div className="bulk-import-content">
          {error && (
            <div className="error-message">
              <span className="material-icons">error</span>
              <span>{error}</span>
            </div>
          )}
          
          {importResult && step !== 'importing' && (
            <div className="import-result">
              <div className={`result-icon ${importResult.error === 0 ? 'success' : 'partial'}`}>
                <span className="material-icons">
                  {importResult.error === 0 ? 'check_circle' : 'warning'}
                </span>
              </div>
              <h4>РРјРїРѕСЂС‚ Р·Р°РІРµСЂС€С‘РЅ</h4>
              <div className="result-stats">
                <p>вњ… РЈСЃРїРµС€РЅРѕ: {importResult.success} / {importResult.total}</p>
                {importResult.new > 0 && <p>вњЁ РќРѕРІС‹С… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№: {importResult.new}</p>}
                {importResult.updated > 0 && <p>рџ”„ РћР±РЅРѕРІР»РµРЅРѕ СЂРѕР»РµР№: {importResult.updated}</p>}
                {importResult.error > 0 && <p className="error-count">вќЊ РћС€РёР±РѕРє: {importResult.error}</p>}
                {importResult.skipped > 0 && <p className="skipped-count">вЏ­пёЏ РџСЂРѕРїСѓС‰РµРЅРѕ: {importResult.skipped}</p>}
              </div>
              <button className="done-btn" onClick={resetAndClose}>
                Р“РѕС‚РѕРІРѕ
              </button>
            </div>
          )}
          
          {!importResult && renderContent()}
        </div>
      </div>
    </div>
  );
};

export default BulkImportModal;
